// ─── MERGE UTILITY ─────────────────────────────────────────────────────────
/**
 * Merge expansion patterns into an existing skeleton table.
 * Usage: mergeDrumExpansion(KICK_SKELETONS, KICK_SKELETONS_EXPANSION);
 */
export function mergeDrumExpansion(target, expansion) {
    for (const family of Object.keys(expansion)) {
        if (!target[family]) {
            target[family] = {};
        }
        for (const variant of Object.keys(expansion[family])) {
            if (target[family][variant]) {
                target[family][variant] = target[family][variant].concat(expansion[family][variant]);
            } else {
                target[family][variant] = [...expansion[family][variant]];
            }
        }
    }
}
